module DFlipFlop (
    input wire clk,
    input wire rst,
    input wire D,
    output reg Q
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            Q <= 0;
        end else begin
            Q <= D;
        end
    end
endmodule
